// Dummy content for the "For You" page. Each user-selected interest expands
// into a handful of tiles. Eventually these will be generated by an LLM +
// web search keyed on the user's city; today, six popular interests have
// curated examples and everything else uses generic search-link tiles.
//
// The page bucket-sorts items into three sections:
//   - Upcoming events  (type: "event" | "class")
//   - Organizations    (type: "organization")
//   - Resources        (type: "community" | "resource")

export type ForYouItemType =
  | "organization"
  | "event"
  | "community"
  | "class"
  | "resource";

export type ForYouSection = "events" | "organizations" | "resources";

export type ForYouItem = {
  id: string;
  title: string;
  type: ForYouItemType;
  icon: string;
  shortDescription: string;
  longDescription: string;
  date?: string;      // e.g. "Every Saturday 9am" or "March 15, 7pm" — events only
  links: { label: string; url: string }[];
  meta?: {
    cost?: string;
    schedule?: string;
    location?: string;
  };
};

const TYPE_LABELS: Record<ForYouItemType, string> = {
  organization: "Organization",
  event: "Event",
  community: "Community",
  class: "Class",
  resource: "Resource",
};

export function getTypeLabel(t: ForYouItemType): string {
  return TYPE_LABELS[t];
}

export function sectionForType(type: ForYouItemType): ForYouSection {
  if (type === "event" || type === "class") return "events";
  if (type === "organization") return "organizations";
  return "resources";
}

