function genericFallback(interest: string): ForYouItem[] {
  const enc = encodeURIComponent(interest);
  return [
    {
      id: `${interest}-luma-eventbrite`,
      title: `${interest} events near you`,
      type: "event",
      icon: "🎟️",
      shortDescription: "Upcoming events on Luma + Eventbrite",
      longDescription: `Luma (lu.ma) is where most professional/tech/hobby events get posted these days; Eventbrite covers a broader range. Search both for one-off and recurring ${interest} events in your area.`,
      date: "Search for upcoming",
      links: [
        { label: "Search Luma", url: `https://lu.ma/discover` },
        {
          label: "Search Eventbrite",
          url: `https://www.eventbrite.com/d/online/${enc}/`,
        },
      ],
    },
    {
      id: `${interest}-meetup`,
      title: `${interest} groups on Meetup`,
      type: "organization",
      icon: "🤝",
      shortDescription: "Recurring groups to join",
      longDescription: `Meetup hosts groups for almost every interest. Search by your interest plus your city to find local recurring meetups — most are free or under $10 and meet 1–4 times per month.`,
      links: [
        {
          label: "Search Meetup",
          url: `https://www.meetup.com/find/?keywords=${enc}`,
        },
      ],
    },
    {
      id: `${interest}-reddit`,
      title: `${interest} on Reddit`,
      type: "community",
      icon: "💬",
      shortDescription: "Subreddits + your city subreddit",
      longDescription: `Two places: a subreddit dedicated to your interest (e.g. r/${interest.replace(/\s+/g, "").toLowerCase()}), and your local city subreddit where you can post asking for recommendations.`,
      links: [
        {
          label: "Search Reddit",
          url: `https://www.reddit.com/search/?q=${enc}`,
        },
      ],
    },
    {
      id: `${interest}-facebook`,
      title: `${interest} Facebook Groups`,
      type: "community",
      icon: "👥",
      shortDescription: "Local online community groups",
      longDescription: `Even if you don't use Facebook day-to-day, the Groups feature is where a lot of recurring local activity organizes — classifieds, recommendations, event invites. Worth a single login.`,
      links: [
        {
          label: "Search Facebook Groups",
          url: `https://www.facebook.com/search/groups/?q=${enc}`,
        },
      ],
    },
    {
      id: `${interest}-city-events`,
      title: "Your city's events calendar",
      type: "resource",
      icon: "🏛️",
      shortDescription: "Local government + tourism board listings",
      longDescription: `Most city governments and visitor bureaus maintain a public events calendar covering everything from festivals to free park programs. Search for your city's official site and bookmark the events page.`,
      links: [
        {
          label: "Search for your city's events",
          url: `https://www.google.com/search?q=${enc}+events+near+me`,
        },
      ],
    },
  ];
}

export function getForYouItems(interest: string): ForYouItem[] {
  return CURATED[interest.toLowerCase()] ?? genericFallback(interest);
}
